package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonNull;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class JsonTreeReaderTest {

    private JsonTreeReader jsonTreeReader;
    private Method nextNullMethod;
    private Method expectMethod;
    private Method popStackMethod;

    @BeforeEach
    public void setUp() throws NoSuchMethodException, Exception {
        // Create a JsonNull element to pass to constructor
        jsonTreeReader = new JsonTreeReader(JsonNull.INSTANCE);

        // Access private methods expect(JsonToken) and popStack()
        expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
        expectMethod.setAccessible(true);

        popStackMethod = JsonTreeReader.class.getDeclaredMethod("popStack");
        popStackMethod.setAccessible(true);

        nextNullMethod = JsonTreeReader.class.getDeclaredMethod("nextNull");
        nextNullMethod.setAccessible(true);
    }

    @Test
    public void testNextNull_withStackSizeGreaterThanZero_incrementsPathIndices() throws Throwable {
        // Setup internal state with stackSize = 2 and pathIndices array
        setField(jsonTreeReader, "stackSize", 2);
        int[] pathIndices = new int[32];
        pathIndices[0] = 5;
        setField(jsonTreeReader, "pathIndices", pathIndices);

        // Override expect(JsonToken.NULL) to do nothing via reflection
        overrideExpect(jsonTreeReader, JsonToken.NULL);

        // Override popStack() to decrement stackSize and return top element via reflection
        overridePopStack(jsonTreeReader);

        // Call nextNull via reflection
        nextNullMethod.invoke(jsonTreeReader);

        // Verify pathIndices[stackSize - 1] incremented by 1
        int[] updatedPathIndices = (int[]) getField(jsonTreeReader, "pathIndices");
        assertEquals(6, updatedPathIndices[1]); // index 1 because stackSize was 2

        // Verify stackSize is decremented by popStack()
        int stackSize = (int) getField(jsonTreeReader, "stackSize");
        assertEquals(1, stackSize);
    }

    @Test
    public void testNextNull_withStackSizeEqualsZero_doesNotIncrementPathIndices() throws Throwable {
        // Setup internal state with stackSize = 0
        setField(jsonTreeReader, "stackSize", 0);
        int[] pathIndices = new int[32];
        setField(jsonTreeReader, "pathIndices", pathIndices);

        // Override expect(JsonToken.NULL) to do nothing via reflection
        overrideExpect(jsonTreeReader, JsonToken.NULL);

        // Override popStack() to decrement stackSize and return top element via reflection
        overridePopStack(jsonTreeReader);

        // Call nextNull via reflection
        nextNullMethod.invoke(jsonTreeReader);

        // Verify pathIndices not incremented (all zero)
        int[] updatedPathIndices = (int[]) getField(jsonTreeReader, "pathIndices");
        for (int val : updatedPathIndices) {
            assertEquals(0, val);
        }

        // Verify stackSize decremented by popStack()
        int stackSize = (int) getField(jsonTreeReader, "stackSize");
        // starting from 0, popStack should decrement to -1 (if implemented so)
        // but to be safe, check <= 0
        assertTrue(stackSize <= 0);
    }

    @Test
    public void testNextNull_expectThrowsException() throws Throwable {
        // Setup stackSize > 0 so pathIndices increment would occur if no exception
        setField(jsonTreeReader, "stackSize", 1);
        int[] pathIndices = new int[32];
        setField(jsonTreeReader, "pathIndices", pathIndices);

        // Create a subclass to override expect to throw IOException
        JsonTreeReader readerWithExpectThrow = new JsonTreeReader(JsonNull.INSTANCE) {
            @Override
            private void expect(JsonToken expected) throws IOException {
                throw new IOException("Expected token missing");
            }
        };

        // Use reflection to invoke nextNull on this subclass instance
        Method nextNull = JsonTreeReader.class.getDeclaredMethod("nextNull");
        nextNull.setAccessible(true);

        InvocationTargetException thrown = assertThrows(InvocationTargetException.class, () -> nextNull.invoke(readerWithExpectThrow));
        Throwable cause = thrown.getCause();
        assertTrue(cause instanceof IOException);
        assertEquals("Expected token missing", cause.getMessage());
    }

    // Helper method to set private field by reflection
    private static void setField(Object target, String fieldName, Object value) throws Exception {
        Field field = JsonTreeReader.class.getDeclaredField(fieldName);
        field.setAccessible(true);
        field.set(target, value);
    }

    // Helper method to get private field by reflection
    private static Object getField(Object target, String fieldName) throws Exception {
        Field field = JsonTreeReader.class.getDeclaredField(fieldName);
        field.setAccessible(true);
        return field.get(target);
    }

    // Helper method to override private expect(JsonToken) method to do nothing via reflection
    private static void overrideExpect(JsonTreeReader reader, JsonToken token) throws Exception {
        // Use reflection to replace the private expect method with a no-op via MethodHandle or proxying not possible,
        // so instead, we patch the expect method via reflection to do nothing:
        // We create a dynamic proxy or use a subclass with overridden expect method.

        // Since expect is private, we cannot mock it with Mockito.
        // So we create a subclass overriding expect to do nothing and copy fields.

        JsonTreeReader noOpExpectReader = new JsonTreeReader(JsonNull.INSTANCE) {
            @Override
            private void expect(JsonToken expected) {
                // do nothing
            }
        };

        // Copy all private fields from original reader to noOpExpectReader
        copyAllFields(reader, noOpExpectReader);

        // Replace the original reader's fields with the no-op's fields via reflection
        // Actually, we want to replace the original reader instance with this subclass instance
        // but since we cannot replace references, we copy fields into the original reader

        // So we copy all private fields from noOpExpectReader back to reader
        copyAllFields(noOpExpectReader, reader);
    }

    // Helper method to override private popStack() method to decrement stackSize and return top element via reflection
    private static void overridePopStack(JsonTreeReader reader) throws Exception {
        // Similar approach: create subclass overriding popStack() method

        JsonTreeReader popStackOverrideReader = new JsonTreeReader(JsonNull.INSTANCE) {
            @Override
            private Object popStack() {
                try {
                    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
                    stackSizeField.setAccessible(true);
                    int stackSize = stackSizeField.getInt(this);
                    if (stackSize == 0) {
                        throw new IllegalStateException("Stack empty");
                    }
                    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
                    stackField.setAccessible(true);
                    Object[] stack = (Object[]) stackField.get(this);
                    Object top = stack[stackSize - 1];
                    stackSizeField.setInt(this, stackSize - 1);
                    return top;
                } catch (Exception e) {
                    throw new RuntimeException(e);
                }
            }
        };

        // Copy all private fields from original reader to popStackOverrideReader
        copyAllFields(reader, popStackOverrideReader);

        // Copy back all fields from popStackOverrideReader to original reader
        copyAllFields(popStackOverrideReader, reader);
    }

    // Helper method to copy all declared fields from source to target
    private static void copyAllFields(Object source, Object target) throws Exception {
        Field[] fields = JsonTreeReader.class.getDeclaredFields();
        for (Field field : fields) {
            field.setAccessible(true);
            Object value = field.get(source);
            field.set(target, value);
        }
    }
}

